## Changes to `echo/frontend/src/app/actions.ts`

### 1. Add `add-card-to-chat` handler (new)
Find the card in kanban state, switch to chat view, append reference text to textarea:

```typescript
if (action === "add-card-to-chat") {
  const workspaceID = target.dataset.workspaceId ?? "";
  const cardID = target.dataset.cardId ?? "";
  if (!workspaceID || !cardID) return;
  dismissContextMenu();

  // Switch to chat view
  const workspace = activeWorkspace();
  if (workspace) {
    state.appMode = "chat";
    state.mobileNavView = "chat";
    state.activeChatKanbanTab.set(workspace.id, "chat");
  }

  // Look up card for title
  const board = kanbanBoardFor(workspaceID);
  const card = kanbanCards(board ?? {}).find((c) => c.id === cardID);
  const label = card ? card.title : cardID;

  // Append reference to chat input
  const textarea = appRoot.querySelector<HTMLTextAreaElement>("[data-chat-input]");
  if (textarea) {
    const ref = `[${cardID}] ${label}\n`;
    textarea.value += ref;
    textarea.focus();
    textarea.setSelectionRange(textarea.value.length, textarea.value.length);
  }

  getAppCallbacks().render();
  return;
}
```

