## Changes to `echo/frontend/src/app/kanban/index.ts`

Export a new function `bindKanbanCardLongPressEvents(root: ParentNode)` that adds pointer event listeners to `article.kanban-card` elements for mobile long-press support.

```typescript
export function bindKanbanCardLongPressEvents(root: ParentNode) {
  root.querySelectorAll<HTMLElement>("article.kanban-card").forEach((card) => {
    let timer: number | null = null;
    let cancelled = false;

    const startTimer = (event: PointerEvent) => {
      cancelled = false;
      timer = window.setTimeout(() => {
        if (!cancelled) {
          triggerContextMenu(card, event);
        }
      }, 500);
    };

    const cancelTimer = () => {
      cancelled = true;
      if (timer !== null) {
        window.clearTimeout(timer);
        timer = null;
      }
    };

    card.addEventListener("pointerdown", startTimer as EventListener);
    card.addEventListener("pointerup", cancelTimer);
    card.addEventListener("pointercancel", cancelTimer);
    card.addEventListener("pointermove", (event: PointerEvent) => {
      // Cancel if finger moved more than 10px (prevents menu on scroll)
      cancelTimer();
    });
  });
}

function triggerContextMenu(card: HTMLElement, event: PointerEvent) {
  const openBtn = card.querySelector<HTMLButtonElement>("button.kanban-card-open");
  if (!openBtn) return;

  const workspace = activeWorkspace();
  if (!workspace) return;

  const cardId = openBtn.dataset.cardId ?? "";
  const titleEl = card.querySelector("strong");
  const cardTitle = titleEl?.textContent ?? cardId;

  // Use pointer position or element center as fallback
  const rect = card.getBoundingClientRect();
  showContextMenu({
    workspaceId: workspace.id,
    displayPath: "",
    cardId,
    cardTitle,
    x: event.clientX || (rect.left + rect.width / 2),
    y: event.clientY || (rect.top + rect.height / 2),
  });
}
```

## Changes to `echo/frontend/src/app/events.ts`

Import and call `bindKanbanCardLongPressEvents(appRoot)` in `bindEvents()`.

## Verification
- Long-press a kanban card on mobile → shows "Add to chat" context menu near touch point
- Quick tap still opens card detail (no interference)
- Scroll doesn't trigger the menu

